#!/usr/bin/perl
use strict;
use warnings;
use CGI;
use CGI::Carp qw(fatalsToBrowser);

my $q = CGI->new;
print $q->header('text/plain');

my $log_dir = '/path/to/log/directory';
my $filename = $q->param('logfile');

if ($filename =~ /^[a-zA-Z0-9._-]+$/) {
    my $file_path = "$log_dir/$filename";
    if (open(my $fh, '<', $file_path)) {
        while (my $line = <$fh>) {
            print $line;
        }
        close($fh);
    } else {
        print "Error opening file: $!";
    }
} else {
    print "Invalid filename.";
}